// ---- Pillar 1: Keyword Research — Google Suggest + Groq clustering → Supabase ----
// Input: { seeds: ['latam market entry', 'ai marketing'] } (optional — uses defaults)
// No paid API needed. Google Suggest is free and unlimited.
// Groq clusters and prioritises the raw suggestions.
// Architecture: parallel suggest fetches → Groq single classify call → Supabase batch upsert.
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const DEFAULT_SEEDS = [
  'latam market entry', 'latin america b2b marketing', 'mexico market strategy',
  'ai marketing implementation', 'ai sales marketing', 'b2b ai tools marketing',
  'go-to-market strategy b2b', 'gtm consulting', 'revenue growth b2b', 'b2b pipeline strategy',
  'latam expansion consulting', 'growth marketing consulting'
];
const seeds = (Array.isArray(b.seeds) && b.seeds.length) ? b.seeds : DEFAULT_SEEDS;

// 1) Fetch Google Suggest for each seed in parallel
async function suggest(query) {
  try {
    const url = `http://suggestqueries.google.com/complete/search?client=firefox&hl=en&q=${encodeURIComponent(query)}`;
    const raw = await this.helpers.httpRequest({ method: 'GET', url, json: false, timeout: 10000 });
    const data = JSON.parse(raw);
    return Array.isArray(data[1]) ? data[1] : [];
  } catch { return []; }
}

const suggestResults = await Promise.allSettled(seeds.map(s => suggest.call(this, s)));
const rawKeywords = [...new Set(
  suggestResults.flatMap(r => r.status === 'fulfilled' ? r.value : [])
    .filter(k => k && k.length > 5 && k.length < 80)
)];

if (!rawKeywords.length) {
  return [{ json: { ok: false, error: 'No suggestions returned from Google Suggest' } }];
}

// 2) Groq: cluster and score the keywords
const SYSTEM = `You are an SEO strategist for Markexis, a B2B consulting firm specialising in:
1. LatAm Market Entry (Mexico, Brazil, Colombia, Argentina, Chile)
2. AI Implementation in Marketing & Sales
3. Revenue Growth & GTM Strategy

Given a list of raw keyword suggestions, return a JSON object:
{
  "keywords": [
    { "keyword": "...", "cluster": "latam|ai|gtm|competitor|other", "intent": "commercial|informational|navigational", "priority": 1-10, "pillar": "latam|ai|gtm" }
  ]
}
Only include keywords with priority >= 6. Mark competitor-targeting keywords cluster="competitor". Prioritise commercial intent highest.`;

const USER = `Keywords to classify (${rawKeywords.length} total):\n${rawKeywords.slice(0, 80).join('\n')}`;

let parsed = { keywords: [] };
const providers = [
  { url: 'https://api.groq.com/openai/v1/chat/completions', key: ENV.GROQ_API_KEY, model: 'llama-3.1-8b-instant' },
  { url: 'https://api.cerebras.ai/v1/chat/completions', key: ENV.CEREBRAS_API_KEY, model: 'llama3.1-70b' },
  { url: 'https://api.sambanova.ai/v1/chat/completions', key: ENV.SAMBANOVA_API_KEY, model: 'Meta-Llama-3.1-405B-Instruct' },
];
for (const p of providers) {
  if (!p.key) continue;
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST', url: p.url,
      headers: { Authorization: `Bearer ${p.key}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: p.model, messages: [{role:'system',content:SYSTEM},{role:'user',content:USER}], temperature: 0.2, max_tokens: 2048, response_format: { type: 'json_object' } }),
      json: true, timeout: 30000
    });
    parsed = JSON.parse(res.choices[0].message.content);
    break;
  } catch { continue; }
}

const toStore = parsed.keywords || [];
if (!toStore.length) return [{ json: { ok: false, error: 'Groq returned no keywords', raw_count: rawKeywords.length } }];

// 3) Batch upsert into Supabase keywords table
const upserts = await Promise.allSettled(toStore.map(kw =>
  this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/keywords?on_conflict=keyword`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates'
    },
    body: JSON.stringify({
      keyword: kw.keyword, pillar: kw.pillar, cluster: `cluster_${kw.cluster}`,
      priority_score: kw.priority, kd: null, volume: null,
      last_checked: new Date().toISOString()
    }),
    json: false, timeout: 15000
  })
));

const ok = upserts.filter(r => r.status === 'fulfilled').length;
return [{ json: { ok: true, raw_suggestions: rawKeywords.length, clustered: toStore.length, stored: ok, seeds_used: seeds.length } }];
